import random
import time

class Lift:
    def __init__(self, num_floors):
        self.current_floor = 0
        self.num_floors = num_floors
        self.passengers = []
        self.direction = 'up'

    def move(self):
        if self.direction == 'up':
            self.current_floor = min(self.current_floor + 1, self.num_floors)
        else:
            self.current_floor = max(self.current_floor - 1, 0)

        print(f"Lift at floor {self.current_floor}")

        self.load_unload_passengers()

        if self.current_floor == 0:
            self.direction = 'up'
        elif self.current_floor == self.num_floors:
            self.direction = 'down'

    def load_unload_passengers(self):
        boarding = []
        exiting = []

        for passenger in self.passengers:
            if passenger.destination == self.current_floor:
                exiting.append(passenger)
            elif self.direction == 'up' and passenger.destination > self.current_floor or \
                 self.direction == 'down' and passenger.destination < self.current_floor:
                boarding.append(passenger)

        for passenger in exiting:
            self.passengers.remove(passenger)
            print(f"Passenger exited at floor {self.current_floor}")

        for passenger in boarding:
            self.passengers.append(passenger)
            print(f"Passenger boarded at floor {self.current_floor}")

class Passenger:
    def __init__(self, origin, destination):
        self.origin = origin
        self.destination = destination

class Building:
    def __init__(self, num_floors, num_lifts):
        self.num_floors = num_floors
        self.num_lifts = num_lifts
        self.lifts = [Lift(num_floors) for _ in range(num_lifts)]
        self.passengers = []

    def simulate_day(self, num_passengers):
        for _ in range(num_passengers):
            origin = random.randint(0, self.num_floors - 1)
            destination = random.randint(0, self.num_floors - 1)
            while destination == origin:
                destination = random.randint(0, self.num_floors - 1)
            self.passengers.append(Passenger(origin, destination))

        while self.passengers:
            for lift in self.lifts:
                lift.move()
            time.sleep(1)

            for passenger in self.passengers[:]:
                for lift in self.lifts:
                    if lift.current_floor == passenger.origin and len(lift.passengers) < 10:
                        lift.passengers.append(passenger)
                        self.passengers.remove(passenger)
                        break

if __name__ == "__main__":
    building = Building(num_floors=50, num_lifts=5)
    building.simulate_day(num_passengers=100)

import random
