class Lift:
    def __init__(self, num_floors):
        self.current_floor = 0
        self.num_floors = num_floors
        self.passengers = []
        self.direction = 'up'

    def move(self):
        if self.direction == 'up':
            self.current_floor = min(self.current_floor + 1, self.num_floors)
        else:
            self.current_floor = max(self.current_floor - 1, 0)

        if self.current_floor == 0:
            self.direction = 'up'
        elif self.current_floor == self.num_floors:
            self.direction = 'down'

        print(f"Lift is on floor {self.current_floor}")

    def board(self, passenger):
        self.passengers.append(passenger)
        print(f"Passenger {passenger.id} boarded the lift on floor {self.current_floor}")

    def deboard(self, passenger):
        self.passengers.remove(passenger)
        print(f"Passenger {passenger.id} deboarded the lift on floor {self.current_floor}")

class Passenger:
    id_counter = 0

    def __init__(self, start_floor, end_floor):
        self.id = Passenger.id_counter
        Passenger.id_counter += 1
        self.start_floor = start_floor
        self.end_floor = end_floor

class Building:
    def __init__(self, num_floors, num_lifts, num_passengers):
        self.num_floors = num_floors
        self.num_lifts = num_lifts
        self.lifts = [Lift(num_floors) for _ in range(num_lifts)]
        self.passengers = [Passenger(random.randint(0, num_floors - 1), random.randint(0, num_floors - 1)) for _ in range(num_passengers)]

    def simulate(self, duration):
        for _ in range(duration):
            # Morning and evening rush hours
            if _ < 3600 or _ >= 57600:
                for passenger in self.passengers:
                    if passenger.start_floor != passenger.end_floor:
                        available_lifts = [lift for lift in self.lifts if lift.current_floor == passenger.start_floor]
                        if available_lifts:
                            available_lifts[0].board(passenger)
                            available_lifts[0].move()
                            if available_lifts[0].current_floor == passenger.end_floor:
                                available_lifts[0].deboard(passenger)
            # Midday
            else:
                for lift in self.lifts:
                    lift.move()

            time.sleep(1)

