import random
import time

class Lift:
    def __init__(self, num_floors):
        self.current_floor = 0
        self.num_floors = num_floors
        self.passengers = []
        self.up_requests = [0] * num_floors
        self.down_requests = [0] * num_floors

    def move(self):
        if self.passengers:
            destination = self.passengers[0]
            if destination > self.current_floor:
                self.current_floor += 1
                self.up_requests[self.current_floor - 1] -= 1
            elif destination < self.current_floor:
                self.current_floor -= 1
                self.down_requests[self.current_floor] -= 1
            if self.current_floor == destination:
                self.passengers.pop(0)
        else:
            if sum(self.up_requests) > sum(self.down_requests):
                self.current_floor += 1
                self.up_requests[self.current_floor - 1] -= 1
            else:
                self.current_floor -= 1
                self.down_requests[self.current_floor] -= 1

class Building:
    def __init__(self, num_floors, num_lifts):
        self.num_floors = num_floors
        self.num_lifts = num_lifts
        self.lifts = [Lift(num_floors) for _ in range(num_lifts)]
        self.crowd_size = 0
        self.crowd_arrival_rate = 0
        self.crowd_departure_rate = 0

    def simulate_day(self, start_time, end_time):
        for hour in range(start_time, end_time):
            self.simulate_hour(hour)

    def simulate_hour(self, hour):
        if 8 <= hour < 10:
            self.crowd_size += self.get_crowd_arrival(self.crowd_arrival_rate)
            self.crowd_departure_rate = 0.1
        elif 17 <= hour < 19:
            self.crowd_departure_rate = self.get_crowd_departure(self.crowd_departure_rate)
            self.crowd_arrival_rate = 0.1
        else:
            self.crowd_arrival_rate = 0.1
            self.crowd_departure_rate = 0.1

        for _ in range(self.crowd_size):
            self.request_lift(random.randint(0, self.num_floors - 1))

        for lift in self.lifts:
            lift.move()

        self.crowd_size -= self.get_crowd_departure(self.crowd_departure_rate)

    def request_lift(self, floor):
        if floor < self.current_floor():
            self.lifts[self.find_nearest_lift(floor)].down_requests[floor] += 1
        else:
            self.lifts[self.find_nearest_lift(floor)].up_requests[floor] += 1

    def current_floor(self):
        return sum(lift.current_floor for lift in self.lifts) // self.num_lifts

    def find_nearest_lift(self, floor):
        nearest_lift = None
        min_distance = float('inf')
        for i, lift in enumerate(self.lifts):
            distance = abs(lift.current_floor - floor)
            if distance < min_distance:
                min_distance = distance
                nearest_lift = i
        return nearest_lift

    def get_crowd_arrival(self, rate):
        return int(random.expovariate(rate))

    def get_crowd_departure(self, rate):
        return int(random.expovariate(rate))

if __name__ == "__main__":
    num_floors = 50
    num_lifts = 5
    building = Building(num_floors, num_lifts)
    building.simulate_day(6, 22)

