        self.passengers = []
        self.is_moving = False
        self.direction = 0

    def add_passenger(self, passenger):
        self.passengers.append(passenger)

    def move(self):
        self.is_moving = True
        if self.direction == 0:
            self.current_floor = 0
        elif self.direction == 1:
            self.current_floor += 1
        else:
            self.current_floor -= 1

        if self.current_floor == 0 or self.current_floor == self.num_floors - 1:
            self.direction *= -1

        for passenger in self.passengers:
            if passenger.destination == self.current_floor:
                self.passengers.remove(passenger)
                print(f"Passenger reached floor {self.current_floor}")
        self.is_moving = False

class Passenger:
    def __init__(self, start_floor, destination_floor):
        self.start_floor = start_floor
        self.destination_floor = destination_floor

class Building:
    def __init__(self, num_floors, num_lifts):
        self.num_floors = num_floors
        self.num_lifts = num_lifts
        self.lifts = [Lift(num_floors) for _ in range(num_lifts)]
        self.passengers = []

    def add_passenger(self, passenger):
        self.passengers.append(passenger)

    def simulate_day(self, start_time, end_time):
        current_time = start_time
        while current_time < end_time:
            self.handle_new_passengers(current_time)
            self.move_lifts()
            time.sleep(0.1)
            current_time += 1

    def handle_new_passengers(self, current_time):
        if current_time < 9:
            new_passengers = [Passenger(random.randint(0, self.num_floors - 1), 0) for _ in range(random.randint(1, 10))]
        elif current_time < 17:
            new_passengers = [Passenger(0, random.randint(0, self.num_floors - 1)) for _ in range(random.randint(1, 5))]
        else:
            new_passengers = [Passenger(random.randint(0, self.num_floors - 1), 0) for _ in range(random.randint(1, 10))]

        for passenger in new_passengers:
            self.add_passenger(passenger)
            print(f"New passenger from floor {passenger.start_floor} to floor {passenger.destination_floor}")

    def move_lifts(self):
        for lift in self.lifts:
            if not lift.is_moving and lift.passengers:
                lift.move()

