import random
import time

class Lift:
    def __init__(self, num_floors):
        self.current_floor = 0
        self.num_floors = num_floors
        self.passengers = []
        self.direction = 'up'

    def move(self):
        if self.direction == 'up':
            self.current_floor = min(self.current_floor + 1, self.num_floors)
            if self.current_floor == self.num_floors:
                self.direction = 'down'
        else:
            self.current_floor = max(self.current_floor - 1, 0)
            if self.current_floor == 0:
                self.direction = 'up'

    def pick_up(self, floor, direction):
        if direction == self.direction:
            self.passengers.append(floor)
            self.passengers.sort()

    def drop_off(self):
        if self.current_floor in self.passengers:
            self.passengers.remove(self.current_floor)

class Building:
    def __init__(self, num_floors, num_lifts):
        self.num_floors = num_floors
        self.num_lifts = num_lifts
        self.lifts = [Lift(num_floors) for _ in range(num_lifts)]
        self.crowd_size = 0
        self.crowd_distribution = [0] * 24

    def simulate(self, duration):
        for hour in range(duration):
            self.update_crowd_size(hour)
            for _ in range(self.crowd_size):
                self.request_lift()
            for lift in self.lifts:
                lift.move()
                lift.drop_off()
            time.sleep(1)

    def update_crowd_size(self, hour):
        if hour < 8 or hour >= 18:
            self.crowd_size = random.randint(0, 10)
            self.crowd_distribution[hour] = self.crowd_size
        else:
            self.crowd_size = random.randint(0, 5)
            self.crowd_distribution[hour] = self.crowd_size

    def request_lift(self):
        floor = random.randint(0, self.num_floors - 1)
        direction = 'up' if floor > 0 else 'down'
        closest_lift = min(self.lifts, key=lambda lift: abs(lift.current_floor - floor))
        closest_lift.pick_up(floor, direction)

