import random
import time

class Lift:
    def __init__(self, num_floors):
        self.current_floor = 0
        self.num_floors = num_floors
        self.passengers = []
        self.direction = 0  # 0 = idle, 1 = up, -1 = down

    def move(self):
        if self.direction == 1:
            self.current_floor = min(self.current_floor + 1, self.num_floors)
        elif self.direction == -1:
            self.current_floor = max(self.current_floor - 1, 0)
        else:
            return

        self.passengers = [p for p in self.passengers if p != self.current_floor]

        if not self.passengers:
            self.direction = 0

    def add_passenger(self, floor):
        self.passengers.append(floor)
        if self.direction == 0:
            self.direction = 1 if floor > self.current_floor else -1

class Building:
    def __init__(self, num_floors, num_lifts):
        self.num_floors = num_floors
        self.lifts = [Lift(num_floors) for _ in range(num_lifts)]
        self.crowd_size = 0
        self.crowd_arrival_rate = 0.1  # percentage of crowd arriving per minute
        self.crowd_departure_rate = 0.05  # percentage of crowd departing per minute

    def run_simulation(self, duration):
        for _ in range(int(duration * 60)):
            self.update_crowd()
            for lift in self.lifts:
                lift.move()
            time.sleep(1)

    def update_crowd(self):
        # Add new arrivals
        new_arrivals = random.randint(0, int(self.crowd_size * self.crowd_arrival_rate))
        for _ in range(new_arrivals):
            self.add_passenger(random.randint(0, self.num_floors - 1))

        # Remove departures
        departures = random.randint(0, int(self.crowd_size * self.crowd_departure_rate))
        self.crowd_size = max(0, self.crowd_size - departures)

    def add_passenger(self, floor):
        self.crowd_size += 1
        min_wait_time = float('inf')
        best_lift = None
        for lift in self.lifts:
            wait_time = abs(lift.current_floor - floor)
            if wait_time < min_wait_time:
                min_wait_time = wait_time
                best_lift = lift
        best_lift.add_passenger(floor)

