class Lift:
    def __init__(self, num_floors):
        self.current_floor = 0
        self.num_floors = num_floors
        self.queue = deque()
        self.is_moving = False
        self.direction = 0

    def call_lift(self, floor):
        self.queue.append(floor)
        if not self.is_moving:
            self.move()

    def move(self):
        self.is_moving = True
        while self.queue:
            if self.direction == 0:
                self.direction = 1 if self.queue[0] > self.current_floor else -1
            if self.direction == 1 and self.current_floor < self.queue[0] or self.direction == -1 and self.current_floor > self.queue[0]:
                self.current_floor += self.direction
                print(f"Lift is on floor {self.current_floor}")
                time.sleep(1)
            else:
                self.queue.popleft()
                self.direction = 0
        self.is_moving = False

