    encrypted_text = ""
    for char in text:
        if char.lower() in key:
            encrypted_text += key[(key.index(char.lower()) + 13) % 26]
        else:
            encrypted_text += char
    return encrypted_text

def decrypt(text):
    key = "abcdefghijklmnopqrstuvwxyz"
    decrypted_text = ""
    for char in text:
        if char.lower() in key:
            decrypted_text += key[(key.index(char.lower()) - 13) % 26]
