import random
import datetime

def run_simulation(num_agents, num_steps):
    agents = [Agent() for _ in range(num_agents)]
    for _ in range(num_steps):
        for agent in agents:
            agent.take_action()
    return agents

class Agent:
    def __init__(self):
        self.energy = random.uniform(0, 100)
        self.sleep_time = 0
        self.awake_time = 0

    def take_action(self):
        if self.sleep_time > 0:
            self.sleep_time -= 1
            self.energy += 5
        else:
            self.energy -= 5
            if self.energy <= 0:
                self.sleep_time = random.randint(6, 12)
                self.awake_time = 0
            else:
                self.awake_time += 1
                if self.awake_time >= 16:
                    self.sleep_time = random.randint(6, 12)
                    self.awake_time = 0

