import datetime
import random

class ActivityTracker:
    def __init__(self, user_name):
        self.user_name = user_name
        self.activities = []
        self.start_time = None
        self.end_time = None

    def start_activity(self, activity_name):
        self.start_time = datetime.datetime.now()
        self.activities.append((activity_name, self.start_time))

    def end_activity(self, activity_name):
        self.end_time = datetime.datetime.now()
        for i, (name, start) in enumerate(self.activities):
            if name == activity_name:
                self.activities[i] = (name, start, self.end_time)
                break

    def get_activity_duration(self, activity_name):
        for name, start, end in self.activities:
            if name == activity_name:
                return end - start
        return None

    def get_daily_activities(self):
        daily_activities = {}
        for name, start, end in self.activities:
            date = start.date()
            if date not in daily_activities:
                daily_activities[date] = []
            daily_activities[date].append((name, start, end))
        return daily_activities

    def generate_report(self):
        report = f"Activity Report for {self.user_name}:\n"
        daily_activities = self.get_daily_activities()
        for date, activities in daily_activities.items():
            report += f"\nDate: {date}\n"
            for name, start, end in activities:
                duration = end - start
                report += f"{name}: {duration}\n"
        return report

# Example usage
tracker = ActivityTracker("John Doe")
tracker.start_activity("Reading")
tracker.end_activity("Reading")
tracker.start_activity("Coding")
tracker.end_activity("Coding")
tracker.start_activity("Exercising")
tracker.end_activity("Exercising")
print(tracker.generate_report())

