    import datetime
    from dateutil import tz

    def convert_datetime(input_datetime):
        from_zone = tz.gettz('UTC')
        to_zone = tz.gettz('America/New_York')

        utc = datetime.datetime.strptime(input_datetime, '%Y-%m-%d %H:%M:%S')
        utc = utc.replace(tzinfo=from_zone)

        central = utc.astimezone(to_zone)
        return central.strftime('%Y-%m-%d %I:%M:%S %p')

    if __name__ == "__main__":
        input_datetime = '2023-04-20 12:00:00'
        output_datetime = convert_datetime(input_datetime)
        print(output_datetime)
